ALTER TABLE `break_schedules` DROP INDEX `break_schedules_agent_date_unique`;

-- Add breakIndex column (0-based index per agent per day)
ALTER TABLE `break_schedules` ADD COLUMN `breakIndex` int NOT NULL DEFAULT 0 AFTER `agentCode`;

-- Add new unique constraint on (agentCode, date, breakIndex)
ALTER TABLE `break_schedules` ADD UNIQUE KEY `break_schedules_agent_date_idx_unique` (`agentCode`, `date`, `breakIndex`);

